final class LocalNetworkPermissionManager: NSObject, ObservableObject, NetServiceBrowserDelegate, NetServiceDelegate {
    @Published var isLocalNetworkAuthorized: Bool = false

    private let browser = NetServiceBrowser()
    private var services: [NetService] = []

    override init() {
        super.init()
        browser.delegate = self
    }

    func startBrowsing() {
        browser.searchForServices(ofType: "_http._tcp.", inDomain: "local.")
    }

    func stopBrowsing() {
        browser.stop()
        services.forEach { $0.stop() }
        services.removeAll()
    }

    func netServiceBrowser(_ browser: NetServiceBrowser, didFind service: NetService, moreComing: Bool) {
        services.append(service)
        service.delegate = self
        service.resolve(withTimeout: 5)
    }

    func netServiceDidResolveAddress(_ sender: NetService) {
        DispatchQueue.main.async {
            self.isLocalNetworkAuthorized = true
        }
    }

    func netService(_ sender: NetService, didNotResolve errorDict: [String : NSNumber]) {
        DispatchQueue.main.async {
            self.isLocalNetworkAuthorized = false
        }
    }
}

